package jetbrains.mps.baseLanguage.unitTest.execution.server;

/*Generated by MPS */

import java.util.List;
import org.jetbrains.annotations.NotNull;
import jetbrains.mps.tool.environment.Environment;
import java.util.Collection;
import jetbrains.mps.baselanguage.unitTest.execution.launcher.ExecutorScript;
import org.jetbrains.mps.openapi.module.SRepository;
import jetbrains.mps.smodel.MPSModuleRepository;
import jetbrains.mps.smodel.ModelAccessHelper;
import org.jetbrains.mps.openapi.persistence.PersistenceFacade;
import jetbrains.mps.persistence.PersistenceRegistry;
import jetbrains.mps.classloading.ClassLoaderManager;
import java.util.ArrayList;
import jetbrains.mps.internal.collections.runtime.CollectionSequence;
import org.jetbrains.mps.openapi.module.SModule;
import jetbrains.mps.classloading.MPSModuleClassLoader;
import jetbrains.mps.project.SModuleOperations;

public abstract class AbstractTestConverter<T> {

  protected List<T> transfigure(@NotNull final Environment env, @NotNull final Collection<ExecutorScript.TestRecord> tests) {
    // XXX likely, need better control over context repository to load test modules from
    final SRepository repo = env.getPlatform().findComponent(MPSModuleRepository.class);
    return new ModelAccessHelper(repo).runReadAction(() -> {
      final PersistenceFacade pf = env.getPlatform().findComponent(PersistenceRegistry.class);
      ClassLoaderManager clm = env.getPlatform().findComponent(ClassLoaderManager.class);
      final ArrayList<T> rv = new ArrayList<>();
      for (ExecutorScript.TestRecord tr : CollectionSequence.fromCollection(tests)) {
        SModule testModule = pf.createModuleReference(tr.myTestModule).resolve(repo);
        final Exception failure;
        final MPSModuleClassLoader moduleCL;
        if (SModuleOperations.classesAvailableToMPS(testModule)) {
          moduleCL = clm.getClassLoader(testModule);
          failure = null;
        } else {
          moduleCL = null;
          if (testModule == null) {
            failure = new Exception(String.format("Failed to find test module %s", tr.myTestModule));
          } else {
            failure = new Exception(String.format("Test module %s is not capable to load classes", tr.myTestModule));
          }
        }

        for (int i = 0; i < tr.myTestQualifiedName.size(); i++) {
          String qualifiedName = tr.myTestQualifiedName.get(i);
          String isTestCaseProp = tr.isTestCase.get(i);
          final boolean isTestCase = Boolean.valueOf(isTestCaseProp).booleanValue();
          final String testFqName;
          final String methodName;
          if (isTestCase) {
            testFqName = qualifiedName;
            methodName = "";
          } else {
            int indexOfLastDot = qualifiedName.lastIndexOf('.');
            if (indexOfLastDot < 0) {
              rv.add(createFailedRequestForMethod(qualifiedName, "", new IllegalStateException(String.format("The qualified name of the test %s does not contain '.'", qualifiedName))));
              continue;
            }
            testFqName = qualifiedName.substring(0, indexOfLastDot);
            methodName = qualifiedName.substring(indexOfLastDot + 1);
          }

          T request;
          if (testModule == null) {
            assert failure != null;
            request = (isTestCase ? createFailedRequestForClass(testFqName, failure) : createFailedRequestForMethod(testFqName, methodName, failure));
          } else {
            try {
              request = (isTestCase ? processTestCase(moduleCL, testFqName) : processTestMethod(moduleCL, testFqName, methodName));
            } catch (Exception ex) {
              request = (isTestCase ? createFailedRequestForClass(testFqName, ex) : createFailedRequestForMethod(testFqName, methodName, ex));
            }
          }
          rv.add(request);
        }
      }
      return rv;
    });
  }

  protected abstract T processTestCase(ClassLoader cl, String fqName) throws Exception;

  protected abstract T processTestMethod(ClassLoader cl, String fqName, String methodName) throws Exception;

  protected abstract T createFailedRequestForClass(String fqName, Exception e);

  protected abstract T createFailedRequestForMethod(String fqName, String methodName, Exception e);
}
